import json
import pickle
import base64
from kafka import KafkaConsumer
from typing import Dict, Any, Callable, List
import logging
from datetime import datetime
from concurrent.futures import ThreadPoolExecutor
import traceback

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class Transaction:
    def __init__(self, transaction_id: str, account_id: str, amount: float, 
                 transaction_type: str, timestamp: str, metadata: Dict = None):
        self.transaction_id = transaction_id
        self.account_id = account_id
        self.amount = amount
        self.transaction_type = transaction_type
        self.timestamp = timestamp
        self.metadata = metadata or {}
    
    def __repr__(self):
        return f"Transaction(id={self.transaction_id}, account={self.account_id}, amount={self.amount})"


class MessageHandler:
    def __init__(self, handler_func: Callable, message_type: str = None):
        self.handler_func = handler_func
        self.message_type = message_type
    
    def handle(self, message: Any) -> Any:
        return self.handler_func(message)


class FinancialTransactionConsumer:
    def __init__(self, bootstrap_servers: List[str], topics: List[str], 
                 group_id: str = 'financial-transaction-group',
                 max_workers: int = 5):
        self.bootstrap_servers = bootstrap_servers
        self.topics = topics
        self.group_id = group_id
        self.max_workers = max_workers
        self.handlers: Dict[str, MessageHandler] = {}
        self.consumer = None
        self.executor = ThreadPoolExecutor(max_workers=max_workers)
        
    def register_handler(self, message_type: str, handler_func: Callable):
        self.handlers[message_type] = MessageHandler(handler_func, message_type)
        logger.info(f"Registered handler for message type: {message_type}")
    
    def deserialize_message(self, raw_value: bytes) -> Any:
        try:
            decoded = raw_value.decode('utf-8')
            data = json.loads(decoded)
            
            if isinstance(data, dict) and '_serialized' in data:
                serialized_data = base64.b64decode(data['_serialized'])
                return pickle.loads(serialized_data)
            
            return data
        except json.JSONDecodeError:
            try:
                return pickle.loads(raw_value)
            except:
                return raw_value.decode('utf-8')
        except Exception as e:
            logger.error(f"Deserialization error: {e}")
            return None
    
    def get_message_type(self, message: Any) -> str:
        if isinstance(message, dict):
            return message.get('message_type', message.get('type', 'unknown'))
        elif hasattr(message, '__class__'):
            return message.__class__.__name__
        return 'unknown'
    
    def process_message(self, message_value: Any, message_key: bytes = None):
        try:
            deserialized_message = self.deserialize_message(message_value)
            
            if deserialized_message is None:
                logger.warning("Failed to deserialize message")
                return
            
            message_type = self.get_message_type(deserialized_message)
            logger.info(f"Processing message type: {message_type}")
            
            handler = self.handlers.get(message_type)
            if handler:
                result = handler.handle(deserialized_message)
                logger.info(f"Handler result for {message_type}: {result}")
            else:
                default_handler = self.handlers.get('default')
                if default_handler:
                    result = default_handler.handle(deserialized_message)
                    logger.info(f"Default handler processed message: {result}")
                else:
                    logger.warning(f"No handler found for message type: {message_type}")
        
        except Exception as e:
            logger.error(f"Error processing message: {e}")
            logger.error(traceback.format_exc())
    
    def start_consuming(self, auto_offset_reset: str = 'latest', 
                       enable_auto_commit: bool = True,
                       consumer_timeout_ms: int = 1000):
        try:
            self.consumer = KafkaConsumer(
                *self.topics,
                bootstrap_servers=self.bootstrap_servers,
                group_id=self.group_id,
                auto_offset_reset=auto_offset_reset,
                enable_auto_commit=enable_auto_commit,
                consumer_timeout_ms=consumer_timeout_ms,
                value_deserializer=None,
                key_deserializer=None
            )
            
            logger.info(f"Consumer started. Listening to topics: {self.topics}")
            
            for message in self.consumer:
                try:
                    logger.info(f"Received message from topic: {message.topic}, partition: {message.partition}, offset: {message.offset}")
                    self.executor.submit(self.process_message, message.value, message.key)
                except Exception as e:
                    logger.error(f"Error in message consumption loop: {e}")
                    
        except Exception as e:
            logger.error(f"Failed to start consumer: {e}")
            raise
    
    def stop_consuming(self):
        if self.consumer:
            self.consumer.close()
            logger.info("Consumer closed")
        self.executor.shutdown(wait=True)
        logger.info("Executor shut down")


def handle_deposit(message):
    logger.info(f"Processing deposit: {message}")
    if isinstance(message, dict):
        amount = message.get('amount', 0)
        account_id = message.get('account_id', 'unknown')
        logger.info(f"Deposit of ${amount} to account {account_id}")
    return {"status": "success", "action": "deposit_processed"}


def handle_withdrawal(message):
    logger.info(f"Processing withdrawal: {message}")
    if isinstance(message, dict):
        amount = message.get('amount', 0)
        account_id = message.get('account_id', 'unknown')
        logger.info(f"Withdrawal of ${amount} from account {account_id}")
    return {"status": "success", "action": "withdrawal_processed"}


def handle_transfer(message):
    logger.info(f"Processing transfer: {message}")
    if isinstance(message, dict):
        amount = message.get('amount', 0)
        from_account = message.get('from_account', 'unknown')
        to_account = message.get('to_account', 'unknown')
        logger.info(f"Transfer of ${amount} from {from_account} to {to_account}")
    return {"status": "success", "action": "transfer_processed"}


def handle_transaction_object(message):
    logger.info(f"Processing Transaction object: {message}")
    if isinstance(message, Transaction):
        logger.info(f"Transaction ID: {message.transaction_id}, Type: {message.transaction_type}, Amount: ${message.amount}")
        
        if message.transaction_type == 'deposit':
            return handle_deposit(message.__dict__)
        elif message.transaction_type == 'withdrawal':
            return handle_withdrawal(message.__dict__)
        elif message.transaction_type == 'transfer':
            return handle_transfer(message.__dict__)
    return {"status": "success", "action": "transaction_object_processed"}


def handle_default(message):
    logger.info(f"Processing unknown message type: {type(message)}")
    logger.info(f"Message content: {message}")
    return {"status": "success", "action": "default_handler"}


